from openai import OpenAI
client = OpenAI()

def detect_thread_ownership_violation(thread_id: str, user_id: str):
    thread = client.beta.threads.retrieve(thread_id)
    # Check if thread metadata contains matching user_id
    thread_metadata = thread.metadata or {}
    owner_id = thread_metadata.get('user_id')
    if not owner_id or owner_id != user_id:
        raise ValueError(f'Unauthorized thread access: expected {user_id}, got {owner_id}')
    return True

def validate_function_auth(schema: dict, arguments: dict, user_context: dict):
    required_auth_fields = ['user_id', 'tenant_id']
    for field in required_auth_fields:
        if field not in arguments or arguments[field] != user_context.get(field):
            raise PermissionError(f'Missing or invalid {field} in function arguments')
    # Validate against schema
    import jsonschema
    jsonschema.validate(arguments, schema)
    return True

async function auditFileSearchPermissions(client: OpenAI, vectorStoreId: string, userId: string) {
  const files = await client.beta.vectorStores.files.list(vectorStoreId);
  for (const file of files.data) {
    const fileMetadata = file.metadata || {};
    if (fileMetadata.owner !== userId) {
      console.warn(`Unauthorized file access: ${file.id} owned by ${fileMetadata.owner}`);
      throw new Error('File permission violation detected');
    }
  }
}

