from openai import OpenAI
client = OpenAI()

def create_authenticated_run(thread_id: str, assistant_id: str, user_id: str):
    run = client.beta.threads.runs.create(
        thread_id=thread_id,
        assistant_id=assistant_id,
        extra_body={
            'metadata': {'user_id': user_id, 'timestamp': str(int(time.time()))}
        }
    )
    return run

async function createIsolatedThread(client: OpenAI, assistantId: string, userId: string) {
  const thread = await client.beta.threads.create({
    metadata: {
      user_id: userId,
      created_at: new Date().toISOString(),
      session_id: crypto.randomUUID()
    }
  });

  // Verify ownership immediately
  const retrieved = await client.beta.threads.retrieve(thread.id);
  if (retrieved.metadata?.user_id !== userId) {
    throw new Error('Thread ownership verification failed');
  }
  return thread;
}
